import React from 'react';

export default function Hero() {
  return (
    <section className="bg-gradient-to-br from-blue-100 to-blue-300 py-20 text-center px-4">
      <h2 className="text-4xl md:text-6xl font-bold text-blue-900 mb-4">
        Find the Best Freelancers for Street Businesses
      </h2>
      <p className="text-lg text-blue-800 mb-8">
        A platform built to empower street talents and micro-entrepreneurs.
      </p>
      <button className="bg-blue-600 text-white px-6 py-2 rounded hover:bg-blue-700 transition">
        Get Started
      </button>
    </section>
  );
}
